/**
 * Build Careers page tables for the 2026 tab from bios_currentdata:
 * Recent Position + Industry, grouped by the same industry sections as other years.
 */

const CATEGORY_ORDER = [
  "Finance & Accounting",
  "Marketing & Sales",
  "Human Resources & Administration",
  "Technology & PM",
  "Consulting",
  "Operations",
  "Venture Capital",
  "Law",
  "Other",
]

function categorizeBrother(industry, recentPosition) {
  const text = `${industry || ""} ${recentPosition || ""}`.toLowerCase()

  if (/\bventure capital\b|\bvc\b/.test(text)) {
    return "Venture Capital"
  }
  if (/\b(attorney|paralegal|legal counsel|\blaw\b|\.law)\b/.test(text)) {
    return "Law"
  }
  if (
    /\b(hr |human resources|human capital|people operations|talent acquisition|recruiter)\b/.test(
      text
    )
  ) {
    return "Human Resources & Administration"
  }
  if (
    /\b(marketing|brand|growth|sales|account executive|communications)\b/.test(text)
  ) {
    return "Marketing & Sales"
  }
  if (
    /\b(software|developer|engineer|data scientist|product manager|product management|technical program|cyber|devops|sre|analytics|machine learning|ml engineer|ui\/ux|ux designer)\b/.test(
      text
    )
  ) {
    return "Technology & PM"
  }
  if (/\b(consulting|consultant)\b/.test(text)) {
    return "Consulting"
  }
  if (/\b(operations|supply chain|logistics|procurement)\b/.test(text)) {
    return "Operations"
  }
  if (
    /\b(quant|finance|accounting|audit|investment banking|private equity|wealth|asset management|equity research|tax|fp&a|treasury|controller)\b/.test(
      text
    ) ||
    /\b(kpmg|deloitte|ey |pwc|p\.w\.c|big four)\b/.test(text)
  ) {
    return "Finance & Accounting"
  }
  return "Other"
}

function isInternshipRole(recentPosition) {
  if (!recentPosition || typeof recentPosition !== "string") {
    return false
  }
  const p = recentPosition.toLowerCase()
  return (
    /\bintern\b/.test(p) ||
    /\bsummer analyst\b/.test(p) ||
    /\bsummer associate\b/.test(p) ||
    /\bco-?op\b/.test(p) ||
    (/\bsummer\b/.test(p) && /\b(analyst|associate|intern)\b/.test(p))
  )
}

function normalizeBrother(node) {
  const first = (node.First_Name || "").trim()
  const last = (node.Last_Name || "").trim()
  if (!first || !last || first === "InsertFirstName") {
    return null
  }
  const recentPosition = (node.Recent_Position || "").trim()
  const industry = (node.Industry || "").trim()
  const name = `${first} ${last}`
  const category = categorizeBrother(industry, recentPosition)
  const intern = isInternshipRole(recentPosition)
  return { name, recentPosition, industry, category, intern, last }
}

function groupByCategory(rows) {
  const map = {}
  CATEGORY_ORDER.forEach((c) => {
    map[c] = []
  })
  rows.forEach((r) => {
    if (!map[r.category]) {
      map[r.category] = []
    }
    map[r.category].push(r)
  })
  CATEGORY_ORDER.forEach((c) => {
    map[c].sort((a, b) => a.last.localeCompare(b.last))
  })
  return map
}

function toGraphqlNodes(grouped) {
  const out = []
  CATEGORY_ORDER.forEach((cat) => {
    const people = grouped[cat] || []
    if (people.length === 0) {
      return
    }
    out.push({ Name: cat })
    people.forEach((p) => {
      out.push({
        Name: p.name,
        Position: p.recentPosition,
        Company: p.industry,
      })
    })
  })
  return { nodes: out }
}

/**
 * @param {Array<Record<string, string>>} biosNodes - allBiosCurrentdataXlsxFormResponses1.nodes
 * @returns {{ fullTime: { nodes: Array }, internships: { nodes: Array } }}
 */
export function buildCareers2026FromBios(biosNodes) {
  const normalized = (biosNodes || [])
    .map(normalizeBrother)
    .filter(Boolean)

  const ftRows = normalized.filter((r) => !r.intern)
  const intRows = normalized.filter((r) => r.intern)

  return {
    fullTime: toGraphqlNodes(groupByCategory(ftRows)),
    internships: toGraphqlNodes(groupByCategory(intRows)),
  }
}
